import{_ as a,o,c as i,a2 as t}from"./chunks/framework.D5wUhsuj.js";const v=JSON.parse('{"title":"Build Process (Vite + Capacitor)","description":"","frontmatter":{},"headers":[],"relativePath":"android/08-build.md","filePath":"android/08-build.md"}'),r={name:"android/08-build.md"};function d(n,e,c,s,l,p){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="build-process-vite-capacitor" tabindex="-1">Build Process (Vite + Capacitor) <a class="header-anchor" href="#build-process-vite-capacitor" aria-label="Permalink to &quot;Build Process (Vite + Capacitor)&quot;">​</a></h1><p>Projekt využívá dvoufázový build proces: webový a nativní.</p><h2 id="_1-webovy-build-vite" tabindex="-1">1. Webový Build (Vite) <a class="header-anchor" href="#_1-webovy-build-vite" aria-label="Permalink to &quot;1. Webový Build (Vite)&quot;">​</a></h2><p>Kód v Reactu je zkompilován a zminifikován do složky <code>dist</code> pomocí příkazu: <code>npm run build</code></p><h2 id="_2-nativni-synchronizace-capacitor" tabindex="-1">2. Nativní Synchronizace (Capacitor) <a class="header-anchor" href="#_2-nativni-synchronizace-capacitor" aria-label="Permalink to &quot;2. Nativní Synchronizace (Capacitor)&quot;">​</a></h2><p>Zkompilované webové soubory jsou překopírovány do Android projektu příkazem: <code>npx cap sync android</code></p><h2 id="_3-sestaveni-apk-gradle" tabindex="-1">3. Sestavení APK (Gradle) <a class="header-anchor" href="#_3-sestaveni-apk-gradle" aria-label="Permalink to &quot;3. Sestavení APK (Gradle)&quot;">​</a></h2><p>Finální balíček je vytvořen pomocí standardního Android Gradle wrapperu (nebo automatizovaně přes GitHub Actions): <code>./gradlew assembleDebug</code> (pro testování) nebo <code>assembleRelease</code> s příslušným keystore certifikátem pro produkci.</p>',8)])])}const b=a(r,[["render",d]]);export{v as __pageData,b as default};
